.container {
  display: flex;
  justify-content: center;
  align-items: center;
  flex-direction: column;
}

.box {
  width: 100px;
  padding: 10px;
  border: 5px solid black;
  margin: 20px;
  /* Total width = 100 + 10*2 + 5*2 = 130px */
}

/* Type, class, id */
button { ... }
.primary { ... }
#header { ... }

/* Attribute + state */
input[type='email']:focus-visible { ... }

/* Combinators */
nav > ul li:first-child { ... }

/* Modern: zero-specificity grouping */
:where(h1, h2, h3) { font-family: serif; }

.hero {
  height: 100vh;
  width: 100vw;
}

/* Component scales with its own font-size */
.button {
  font-size: 1rem;
  padding: 0.5em 1em;       /* scales with button text */
  border-radius: 0.25em;
}

/* Bigger variant — padding scales automatically */
.button-lg { font-size: 1.5rem; }

/* root-relative: rem instead */
html { font-size: 16px; }
.heading { font-size: 2rem; }   /* 32px */

.layout {
  display: grid;
  grid-template-columns: 200px 1fr;
  grid-template-rows: auto 1fr auto;
  gap: 20px;
}

button:hover { background: darkblue; }

li:nth-child(3n) { color: red; }

input:invalid { border-color: red; }

/* Specificity: 0, 1, 0 */
.btn { color: red; }

/* Specificity: 1, 0, 0 (Wins) */
#main-btn { color: blue; }

/* Specificity: 1, 1, 0 (Wins) */
#container .btn { color: green; }

body { color: #333; }

p { 
  /* Inherits color from body by default */ 
}

.no-inherit {
  color: initial; /* Forces it to reset */
}

* {
  box-sizing: border-box;
}

.element {
  width: 100px;
  padding: 10px;
  /* Total width is exactly 100px */
}

.modal {
  position: fixed;
  z-index: 1000;
}

.backdrop {
  position: fixed;
  z-index: 999;
}

:root {
  --primary-color: #007bff;
}

.button {
  background-color: var(--primary-color);
}

@keyframes slideIn {
  from { transform: translateX(-100%); }
  to { transform: translateX(0); }
}

.section-header {
  position: sticky;
  top: 0;             /* sticks here when scrolled past */
  background: white;
  z-index: 1;
}

/* Sticky only works inside a scrollable container */
.scroll-area { overflow-y: auto; max-height: 80vh; }

a::after {
  content: ' ↗';
  font-size: 0.8em;
}

p::first-letter {
  font-size: 2em;
  font-weight: bold;
}

/* Block */
.card { }
/* Element */
.card__title { }
/* Modifier */
.card--featured { }

h1 {
  font-size: clamp(1rem, 5vw, 3rem);
}

.parent {
  position: relative;
  z-index: 1;
  opacity: 0.99; /* Creates new stacking context */
}
.child {
  position: absolute;
  z-index: 9999; /* Trapped in parent's context */
}

.box {
  /* Instead of margin-left */
  margin-inline-start: 20px;
  /* Instead of width */
  inline-size: 100%;
}

.button {
  anchor-name: --btn;
}

.tooltip {
  position: absolute;
  position-anchor: --btn;
  top:  anchor(bottom);     /* sit below the button */
  left: anchor(center);     /* horizontally centered */
  translate: -50% 8px;
}

.widget {
  contain: layout paint;
}

.child-grid {
  display: grid;
  grid-template-columns: subgrid;
  grid-column: span 3;
}

.container {
  container-type: inline-size;
}

@container (min-width: 400px) {
  .card { display: flex; }
}

@layer base, components, utilities;

@layer utilities {
  .hidden { display: none !important; }
}
